package com.dbms.model;
public class TaskItem { private final int taskId,roadmapId; private final String title; private String status; public TaskItem(int taskId,int roadmapId,String title,String status){this.taskId=taskId;this.roadmapId=roadmapId;this.title=title;this.status=status;} public int getTaskId(){return taskId;} public int getRoadmapId(){return roadmapId;} public String getTitle(){return title;} public String getStatus(){return status;} public void setStatus(String status){this.status=status;} public boolean isCompleted(){return "Completed".equalsIgnoreCase(status)||"Done".equalsIgnoreCase(status);} }
